fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val sorted_nums = nums.sortedTo<Array<Long>>()
    var max_k = 0L

    for (k in 0L until n) {
        val current_nums = nums.copyOf()
        val visited = BooleanArray(n)

        var sorted = true
        for (i in 0 until n) {
            if (visited[i]) continue
            var found = false
            for (j in i until n) {
                if (!visited[j] && (current_nums[i] and current_nums[j]) == k) {
                    current_nums[i].also { current_nums[j] = it }
                    current_nums[j].also { current_nums[i] = it }
                    visited[j] = true
                    found = true
                    break
                }
            }
            if (!found) {
                sorted = false
                break
            }
        }

        if (sorted && current_nums.contentEquals(sorted_nums)) {
            max_k = k
        }
    }

    return max_k
}
